const expireJobPostings = `-- name: ExpireJobPostings :many
UPDATE hrms.job_postings
SET is_published = FALSE,
    job_status = 'Expired',
    updated_at = NOW()
WHERE tenant_id = $1
  AND is_published
  AND expiry_date IS NOT NULL
  AND expiry_date < CURRENT_DATE
  AND NOT inactive
RETURNING id, tenant_id, job_requisition_id, code, title, job_summary, description, job_category, department_id, industry, employment_type_id, work_mode, role_type, min_experience, max_experience, min_salary, max_salary, salary_currency, salary_period, is_salary_visible, job_status, publish_date, expiry_date, is_published, inactive, created_at, created_by, updated_at, updated_by
`

func (q *Queries) ExpireJobPostings(ctx context.Context, tenantID uuid.UUID) ([]HrmsJobPosting, error) {
	rows, err := q.db.Query(ctx, expireJobPostings, tenantID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []HrmsJobPosting
	for rows.Next() {
		var i HrmsJobPosting
		if err := rows.Scan(
			&i.ID,
			&i.TenantID,
			&i.JobRequisitionID,
			&i.Code,
			&i.Title,
			&i.JobSummary,
			&i.Description,
			&i.JobCategory,
			&i.DepartmentID,
			&i.Industry,
			&i.EmploymentTypeID,
			&i.WorkMode,
			&i.RoleType,
			&i.MinExperience,
			&i.MaxExperience,
			&i.MinSalary,
			&i.MaxSalary,
			&i.SalaryCurrency,
			&i.SalaryPeriod,
			&i.IsSalaryVisible,
			&i.JobStatus,
			&i.PublishDate,
			&i.ExpiryDate,
			&i.IsPublished,
			&i.Inactive,
			&i.CreatedAt,
			&i.CreatedBy,
			&i.UpdatedAt,
			&i.UpdatedBy,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

