func (q *Queries) ListCandidateApplicationEvents(ctx context.Context, arg ListCandidateApplicationEventsParams) ([]HrmsCandidateApplicationEvent, error) {
	rows, err := q.db.Query(ctx, listCandidateApplicationEvents, arg.TenantID, arg.ApplicationID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []HrmsCandidateApplicationEvent
	for rows.Next() {
		var i HrmsCandidateApplicationEvent
		if err := rows.Scan(
			&i.ID,
			&i.TenantID,
			&i.ApplicationID,
			&i.FromStatus,
			&i.ToStatus,
			&i.Action,
			&i.Reason,
			&i.Remarks,
			&i.Inactive,
			&i.CreatedAt,
			&i.CreatedBy,
			&i.UpdatedAt,
			&i.UpdatedBy,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const listCandidateApplications = `-- name: ListCandidateApplications :many
SELECT ca.id, ca.tenant_id, ca.candidate_id, ca.job_posting_id, ca.resume_url, ca.cover_letter, ca.current_ctc, ca.expected_ctc, ca.notice_period, ca.referred_by, ca.source, ca.status, ca.comments, ca.inactive, ca.created_at, ca.created_by, ca.updated_at, ca.updated_by, ca.applied_at, ca.status_changed_at, ca.status_changed_by, ca.rejection_reason, ca.withdrawal_reason, ca.source_detail, ca.duplicate_of_application_id,
       c.firstname AS candidate_firstname,
       c.lastname AS candidate_lastname,
       c.email AS candidate_email,
       c.phone AS candidate_phone,
       jp.title AS job_posting_title,
       jp.code AS job_posting_code,
       COUNT(*) OVER()::bigint AS total_count
FROM hrms.candidate_applications ca
LEFT JOIN hrms.candidates c ON c.id = ca.candidate_id AND c.tenant_id = ca.tenant_id
LEFT JOIN hrms.job_postings jp ON jp.id = ca.job_posting_id AND jp.tenant_id = ca.tenant_id
WHERE ca.tenant_id = $1
  AND NOT ca.inactive
  AND ($2::text IS NULL OR ca.status = $2::text)
  AND ($3::uuid IS NULL OR ca.candidate_id = $3::uuid)
  AND ($4::uuid IS NULL OR ca.job_posting_id = $4::uuid)
  AND (
    $5::text IS NULL
    OR c.firstname ILIKE '%' || $5::text || '%'
    OR c.lastname ILIKE '%' || $5::text || '%'
    OR c.email ILIKE '%' || $5::text || '%'
    OR ca.source ILIKE '%' || $5::text || '%'
    OR ca.referred_by ILIKE '%' || $5::text || '%'
    OR ca.comments ILIKE '%' || $5::text || '%'
    OR jp.title ILIKE '%' || $5::text || '%'
    OR jp.code ILIKE '%' || $5::text || '%'
  )
ORDER BY ca.updated_at DESC, ca.created_at DESC
OFFSET $6
LIMIT $7
`

