const listJobRequisitions = `-- name: ListJobRequisitions :many
SELECT
    jr.id,
    jr.tenant_id,
    jr.job_position_id,
    jp.code AS job_position_code,
    jp.total_position AS position_total_headcount,
    jp.budgeted_cost AS position_budgeted_cost,
    jr.code,
    jr.title,
    jr.level,
    jr.category,
    jr.department_id,
    d.name AS department_name,
    jr.employment_type_id,
    et.name AS employment_type_name,
    jr.description,
    jr.work_mode,
    jr.total_openings,
    jr.reason_for_hire,
    jr.min_salary,
    jr.max_salary,
    jr.currency,
    jr.target_hire_date,
    jr.expected_closure_date,
    jr.requested_by,
    jr.requested_date,
    jr.is_approved,
    jr.approved_by,
    jr.approved_date,
    jr.priority,
    jr.status,
    jr.notes,
    COALESCE(logs.log_count, 0)::int AS log_count,
    jr.inactive,
    jr.created_at,
    jr.created_by,
    jr.updated_at,
    jr.updated_by
FROM hrms.job_requisitions jr
JOIN hrms.job_positions jp ON jp.tenant_id = jr.tenant_id AND jp.id = jr.job_position_id
LEFT JOIN hrms.departments d ON d.tenant_id = jr.tenant_id AND d.id = jr.department_id AND NOT d.inactive
LEFT JOIN hrms.employment_types et ON et.tenant_id = jr.tenant_id AND et.id = jr.employment_type_id AND NOT et.inactive
LEFT JOIN LATERAL (
    SELECT COUNT(*) AS log_count
    FROM hrms.job_requisition_logs jrl
    WHERE jrl.tenant_id = jr.tenant_id AND jrl.job_requisition_id = jr.id AND NOT jrl.inactive
) logs ON TRUE
WHERE jr.tenant_id = $1
  AND ($2::text IS NULL OR jr.status = $2::text)
  AND ($3::uuid IS NULL OR jr.job_position_id = $3::uuid)
  AND ($4::uuid IS NULL OR jr.department_id = $4::uuid)
  AND (
      $5::text IS NULL
      OR jr.title ILIKE '%' || $5::text || '%'
      OR jr.code ILIKE '%' || $5::text || '%'
      OR jr.reason_for_hire ILIKE '%' || $5::text || '%'
  )
  AND NOT jr.inactive
ORDER BY jr.created_at DESC
LIMIT $7 OFFSET $6
`

